try {
  const items = $input.all();
  const results = [];
  for (const item of items) {
    let strategy;
    try {
      const text = item.json.content[0].text;
      strategy = JSON.parse(text);
    } catch(e) {
      const text = item.json.content[0].text;
      const match = text.match(/\{[\s\S]*\}/);
      if (match) {
        strategy = JSON.parse(match[0]);
      } else {
        strategy = {
          week1: 'Establish brand presence and audit current marketing',
          week2: 'Launch initial campaigns on key channels',
          week3: 'Optimize based on early data',
          week4: 'Scale winning strategies and report results',
          key_channels: ['instagram', 'facebook', 'email'],
          target_audience: 'general consumers',
          budget_recommendation: 'Start with $500/month and scale based on ROI',
          kpis: ['reach', 'engagement_rate', 'conversion_rate', 'roas']
        };
      }
    }
    // Preserve upstream fields
    const upstream = $('Extract Business Data').first().json;
    results.push({json: {
      id: upstream.id || '',
      business_name: upstream.business_name || '',
      email: upstream.email || '',
      industry: upstream.industry || '',
      strategy: JSON.stringify(strategy),
      week1: strategy.week1 || '',
      week2: strategy.week2 || '',
      week3: strategy.week3 || '',
      week4: strategy.week4 || '',
      key_channels: strategy.key_channels || [],
      budget_recommendation: strategy.budget_recommendation || '',
      kpis: strategy.kpis || []
    }});
  }
  return results;
} catch(e) {
  return [{json:{error: e.message}}];
}
